// // This module decrements a 2-bit binary counter on the rising edge of the input clock signal (clk_in). When the counter reaches a value of 0, it resets back to 2. The current value of the counter is output as a 2-bit signal (count_out).
module top_module(
    input wire clk_in,
    output[1:0] count_out
    );reg[1:0] count = 0;  
    always @(posedge clk_in)
        begin
        count <= (count == 2)? 0: count + 1; 
        end
    assign count_out = count; 
endmodule
